import React from 'react';
import { FiBell, FiExternalLink } from 'react-icons/fi';
import { generateDynamicData } from '../../utils/dynamicData';

interface Props { skillId?: string; }

const TrendAlerts: React.FC<Props> = ({ skillId }) => {
  const data = generateDynamicData(skillId);

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-200">
        <h3 className="text-2xl font-bold text-gray-900 mb-6 flex items-center gap-2">
          <FiBell className="text-yellow-500" /> Industry Trends for {data.skill}
        </h3>

        <div className="space-y-4">
          {[
            { title: `${data.skill} adoption surges in enterprise sectors`, source: 'TechCrunch', time: '2 days ago', type: 'News' },
            { title: `New major framework update changes ${data.skill} best practices`, source: 'GitHub Blog', time: '1 week ago', type: 'Update' },
            { title: `Demand for ${data.skill} engineers outpaces supply`, source: 'LinkedIn Insights', time: '2 weeks ago', type: 'Market' },
          ].map((alert, i) => (
            <div key={i} className="p-4 bg-gray-50 border border-gray-100 rounded-xl hover:shadow-md hover:border-blue-200 transition-all group flex justify-between items-center cursor-pointer">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded-full ${
                    alert.type === 'News' ? 'bg-blue-100 text-blue-700' :
                    alert.type === 'Update' ? 'bg-purple-100 text-purple-700' : 'bg-green-100 text-green-700'
                  }`}>
                    {alert.type}
                  </span>
                  <span className="text-xs text-gray-500">{alert.time} • {alert.source}</span>
                </div>
                <h4 className="font-bold text-gray-900 group-hover:text-blue-600 transition-colors">{alert.title}</h4>
              </div>
              <FiExternalLink className="text-gray-400 group-hover:text-blue-500 opacity-0 group-hover:opacity-100 transition-all" />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default TrendAlerts;
